export declare const GENERIC_PROMPT_ADDITION = "## General Review Areas\n\n- Security: hardcoded credentials, secrets in code, insecure defaults\n- Error handling: missing error checks, silent failures\n- Resource management: unclosed handles, memory leaks\n- Input validation: missing validation on user-controlled input\n- Logging: sensitive data in logs, missing error context\n- Configuration: hardcoded values that should be configurable\n- Documentation: missing comments on complex logic\n- Testing: untestable code structure, missing edge cases";
